formulas.expression:
IF(
    LEN(
        IF(
            BEGINS({!$Record.Name}, "Quote for"),
            {!$Record.zqu__Number__c} & " - " & SUBSTITUTE({!$Record.Name}, "Quote for", ""),
            {!$Record.zqu__Number__c} & " - " & {!$Record.Name}
        )
    ) > 80,
    LEFT(
        IF(
            BEGINS({!$Record.Name}, "Quote for"),
            {!$Record.zqu__Number__c} & " - " & SUBSTITUTE({!$Record.Name}, "Quote for", ""),
            {!$Record.zqu__Number__c} & " - " & {!$Record.Name}
        ),
        80
    ),
    IF(
        BEGINS({!$Record.Name}, "Quote for"),
        {!$Record.zqu__Number__c} & " - " & SUBSTITUTE({!$Record.Name}, "Quote for", ""),
        {!$Record.zqu__Number__c} & " - " & {!$Record.Name}
    )
)
